<?php
namespace App\Http\Controllers\Tenant;
use App\Http\Controllers\Controller;use App\Models\{Department,Project,Task,TaskCategory,Team,User};use App\Services\Tasks\TaskNumberService;use App\Support\CurrentWorkspace;use Illuminate\Http\Request;use Illuminate\Support\Facades\DB;use Illuminate\Validation\Rule;
class TaskController extends Controller{use Concerns;public function index(Request $r,CurrentWorkspace $cw){$w=$this->ws($cw);$q=Task::query()->with(['project','creator','assignedUsers'])->latest();foreach(['status','priority','project_id','department_id','team_id'] as $f)if($r->filled($f))$q->where($f,$r->$f);if($r->filled('assignee'))$q->whereHas('assignedUsers',fn($x)=>$x->where('users.id',$r->integer('assignee')));if($r->filled('due')){if($r->due==='today')$q->whereDate('due_date',today());if($r->due==='overdue')$q->whereDate('due_date','<',today())->where('status','!=','completed');}if($r->filled('view')){if($r->view==='my')$q->whereHas('assignedUsers',fn($x)=>$x->where('users.id',$r->user()->id));if($r->view==='today')$q->whereDate('due_date',today());if($r->view==='overdue')$q->whereDate('due_date','<',today())->where('status','!=','completed');if($r->view==='proof')$q->where('proof_required',true);if($r->view==='approval')$q->where('approval_required',true)->where('approval_status','pending');}if($r->filled('search'))$q->where(fn($x)=>$x->where('title','like','%'.$r->search.'%')->orWhere('task_number','like','%'.$r->search.'%'));return view('tenant.tasks.index',['tasks'=>$q->paginate(15)->withQueryString(),'projects'=>Project::all(),'users'=>$w->users()->get(),'departments'=>Department::all(),'teams'=>Team::all()]);}public function create(CurrentWorkspace $cw){return view('tenant.tasks.create',$this->formData($cw));}public function store(Request $r,CurrentWorkspace $cw,TaskNumberService $num){$this->requirePerm('tenant.tasks.create');$w=$this->ws($cw);$data=$this->validated($r,$w);$task=DB::transaction(function()use($data,$r,$w,$num){$cat=!empty($data['task_category_id'])?TaskCategory::find($data['task_category_id']):null;$task=Task::create($data+['workspace_id'=>$w->id,'task_number'=>$num->next($w),'created_by'=>$r->user()->id,'proof_required'=>($data['proof_required']??false)||($cat?->proof_required??false),'approval_required'=>($data['approval_required']??false)||($cat?->approval_required??false),'approval_status'=>($data['approval_required']??false)||($cat?->approval_required??false)?'pending':null]);$this->syncPeople($task,$r,$w,true);foreach((array)$r->input('checklist_items',[]) as $i=>$title)if(trim($title)!=='')$task->checklistItems()->create(['workspace_id'=>$w->id,'title'=>$title,'sort_order'=>$i]);$this->logTask($task,'created',[],['title'=>$task->title],'Task created');return $task;});return redirect('/tasks/'.$task->id)->with('status','Task created.');}public function show(Task $task){return view('tenant.tasks.show',['task'=>$task->load(['category','project','department','team','creator','assignedUsers','watchers','checklistItems','comments.user','attachments','activityLogs.user'])]);}public function edit(Task $task,CurrentWorkspace $cw){$this->requirePerm('tenant.tasks.update');return view('tenant.tasks.edit',$this->formData($cw)+['task'=>$task->load(['assignedUsers','watchers'])]);}public function update(Request $r,Task $task,CurrentWorkspace $cw){$this->requirePerm($r->status==='completed'?'tenant.tasks.complete':'tenant.tasks.update');$w=$this->ws($cw);$data=$this->validated($r,$w,$task->id);$old=$task->only(['status','priority','title','due_date']);if(($data['status']??$task->status)==='completed'&&$task->status!=='completed'){if($task->proof_required && !$task->proofs()->whereIn('status',['submitted','approved'])->exists())return back()->withErrors(['proof'=>'Proof is required before completing this task.']);if($task->approval_required)return redirect('/tasks/'.$task->id)->withErrors(['approval'=>'This task requires manager approval. Please request approval.']);$data['completed_at']=now();$data['completed_by']=$r->user()->id;}$task->update($data);if($old['status']!==$task->status)$this->logTask($task,'status_changed',['status'=>$old['status']],['status'=>$task->status],'Task status changed');$this->syncPeople($task,$r,$w,false);return redirect('/tasks/'.$task->id)->with('status','Task updated.');}public function destroy(Task $task){$this->requirePerm('tenant.tasks.delete');$task->delete();return redirect('/tasks')->with('status','Task deleted.');}private function validated(Request $r,$w):array{return $r->validate(['title'=>'required|string|max:255','description'=>'nullable|string','task_category_id'=>['nullable',Rule::exists('task_categories','id')->where('workspace_id',$w->id)],'project_id'=>['nullable',Rule::exists('projects','id')->where('workspace_id',$w->id)],'department_id'=>['nullable',Rule::exists('departments','id')->where('workspace_id',$w->id)],'team_id'=>['nullable',Rule::exists('teams','id')->where('workspace_id',$w->id)],'priority'=>['required',Rule::in(Task::PRIORITIES)],'status'=>['required',Rule::in(Task::STATUSES)],'start_date'=>'nullable|date','due_date'=>'nullable|date|after_or_equal:start_date','estimated_hours'=>'nullable|numeric|min:0','proof_required'=>'boolean','approval_required'=>'boolean']);}private function formData(CurrentWorkspace $cw):array{$w=$this->ws($cw);return['categories'=>TaskCategory::where('is_active',true)->get(),'projects'=>Project::where('status','active')->get(),'departments'=>Department::all(),'teams'=>Team::all(),'users'=>$w->users()->wherePivot('status','active')->get(),'statuses'=>Task::STATUSES,'priorities'=>Task::PRIORITIES];}private function syncPeople(Task $task,Request $r,$w,bool $new):void{$ids=array_map('intval',(array)$r->input('assignees',[]));$watch=array_map('intval',(array)$r->input('watchers',[]));$valid=$this->workspaceUserIds($w);abort_if(array_diff($ids,$valid)||array_diff($watch,$valid),422,'Only current workspace users may be selected.');if($ids)$this->requirePerm('tenant.tasks.assign');$old=$task->assignedUsers()->pluck('users.id')->all();$task->assignedUsers()->syncWithPivotValues($ids,['workspace_id'=>$w->id,'assigned_by'=>$r->user()->id,'assigned_at'=>now(),'role'=>'assignee']);$task->watchers()->syncWithPivotValues($watch,['workspace_id'=>$w->id]);if($new||$old!=$ids)$this->logTask($task,'assignment_changed',['assignees'=>$old],['assignees'=>$ids],'Task assignments changed');}}
